import{f as e}from"./app.f26a487c.js";import{_ as o}from"./plugin-vue_export-helper.21dcd24c.js";var a="/images/logscreenshot.png";const s={},n=e(`<h1 id="sql-logging" tabindex="-1"><a class="header-anchor" href="#sql-logging" aria-hidden="true">#</a> SQL Logging</h1><p>go-doudou uses <code>GddDB</code> and <code>GddTx</code> structs to wrap <code>*sqlx.DB</code> to implement SQL logging feature. There is no direct relationship between this feature and ddl tool, that means you can use <code>GddDB</code> and <code>GddTx</code> in your own custom database operation code as a drop-in replacement for <code>*sqlx.DB</code>. You can call package level static function <code>wrapper.NewGddDB</code> to create <code>GddDB</code> instance and call <code>BeginTxx</code> method to create <code>GddTx</code> instance.</p><p>go-doudou provides <code>ISqlLogger</code> interface from <code>toolkit/sqlext/logger</code> package, which developers can implement. Developers can also use an out-of-box <code>SqlLogger</code> struct. There is also a factory function <code>NewSqlLogger</code> for you to create <code>SqlLogger</code> instance from <code>toolkit/sqlext/logger</code>. You just need to pass the instance to <code>wrapper.NewGddDB</code> function to create <code>GddDB</code> instance, then pass it to generated dao layer factory function to create dao instance, then you can call CRUD methods from the dao instance and SQL whose parameter placeholders have been already substituted with values will be printed automatically.</p><div class="language-go ext-go line-numbers-mode"><pre class="shiki" style="background-color:#1E1E1E;"><code><span class="line"><span style="color:#9CDCFE;">gdddb</span><span style="color:#D4D4D4;"> := wrapper.</span><span style="color:#DCDCAA;">NewGddDB</span><span style="color:#D4D4D4;">(db, wrapper.</span><span style="color:#DCDCAA;">WithLogger</span><span style="color:#D4D4D4;">(logger.</span><span style="color:#DCDCAA;">NewSqlLogger</span><span style="color:#D4D4D4;">(log.</span><span style="color:#DCDCAA;">Default</span><span style="color:#D4D4D4;">())))</span></span>
<span class="line"><span style="color:#9CDCFE;">u</span><span style="color:#D4D4D4;"> := dao.</span><span style="color:#DCDCAA;">NewUserDao</span><span style="color:#D4D4D4;">(gdddb)</span></span>
<span class="line"><span style="color:#6A9955;">// use u to operate database</span></span>
<span class="line"><span style="color:#6A9955;">// got, err := u.UpsertNoneZero(context.Background(), user)</span></span>
<span class="line"></span></code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Besides SQL statements, go-doudou will also extract request id and trace id from <code>context.Context</code> and print them at the same time.</p><p><img src="`+a+'" alt="go-doudou\u8F93\u51FAsql\u67E5\u8BE2\u65E5\u5FD7"></p><p>If you use the default implementation <code>SqlLogger</code>, you should also need to set environment variable <code>GDD_SQL_LOG_ENABLE</code> to <code>true</code>.</p>',7);function t(c,d){return n}var p=o(s,[["render",t]]);export{p as default};
